<style>
/* ═══════════════════════════════════════════════════════════
   ONLINE REPUTATION MANAGEMENT — EDITORIAL LAYOUT
   Deep Indigo #4338ca + Violet #7c3aed
   Following Content Marketing / Email editorial pattern
═══════════════════════════════════════════════════════════ */
:root {
  --orm-primary: #4338ca;
  --orm-accent:  #7c3aed;
  --orm-dark:    #1e1b4b;
  --orm-slate:   #0f0e1a;
  --orm-light:   #eef2ff;
  --orm-border:  #c7d2fe;
  --orm-cream:   #f5f3ff;
  --orm-muted:   #818cf8;
  --orm-text:    #57534e;
  --orm-grad:    linear-gradient(135deg, #4338ca, #7c3aed);
  --orm-danger:  #dc2626;
  --orm-warn:    #d97706;
  --orm-safe:    #059669;
}
*, *::before, *::after { box-sizing: border-box; }

/* ════════════════════════════════════════════════════
   ZONE A: WHITE HERO — Seamless with header
═════════════════════════════════════════════════════ */
.orm-modern-hero { position: relative; padding: 150px 0 100px; background: radial-gradient(120% 120% at 80% 0%, #eef2ff 0%, #ffffff 60%); overflow: hidden; }
@media (max-width: 991px) {
  .orm-modern-hero { padding: 130px 0 70px; }
}
.orm-modern-hero .hero-content { position: relative; z-index: 2; padding-top: 0; }
.orm-modern-hero h1 { font-size: clamp(40px, 5vw, 64px); font-weight: 900; color: #1c1917; line-height: 1.1; margin-bottom: 20px; letter-spacing: -1.5px; }
.orm-modern-hero h3 { font-size: 22px; font-weight: 600; color: var(--orm-primary); margin-bottom: 24px; line-height: 1.4; }
.orm-modern-hero p { font-size: 18px; color: #57534e; line-height: 1.7; margin-bottom: 35px; max-width: 90%; }
.orm-hero-buttons { display: flex; gap: 15px; align-items: center; flex-wrap: wrap; }
.orm-cta-btn-main { display: inline-flex; align-items: center; gap: 10px; background: var(--orm-grad); color: #fff; font-size: 15px; font-weight: 700; padding: 16px 32px; border-radius: 6px; text-decoration: none; transition: all .3s; box-shadow: 0 4px 20px rgba(67,56,202,.22); border: none; }
.orm-cta-btn-main:hover { transform: translateY(-2px); box-shadow: 0 8px 28px rgba(67,56,202,.32); color: #fff; }
.orm-cta-btn-outline { background: #fff; color: var(--orm-primary); padding: 16px 32px; border-radius: 6px; font-weight: 700; font-size: 15px; text-decoration: none; transition: all 0.3s; border: 1.5px solid var(--orm-border); display: inline-flex; align-items: center; }
.orm-cta-btn-outline:hover { border-color: var(--orm-primary); color: var(--orm-primary); background: var(--orm-light); }
.orm-hero-visual { position: relative; z-index: 2; text-align: right; }
.orm-hero-visual img.main-img { max-width: 100%; border-radius: 24px; box-shadow: 0 30px 60px rgba(0,0,0,0.08); position: relative; z-index: 2; border: 4px solid #fff; }
.orm-hero-visual .floating-card { position: absolute; background: rgba(255,255,255,0.9); backdrop-filter: blur(10px); padding: 15px 20px; border-radius: 12px; border: 1px solid rgba(255,255,255,0.6); box-shadow: 0 15px 30px rgba(0,0,0,0.06); z-index: 3; display: flex; align-items: center; gap: 12px; animation: float 6s ease-in-out infinite; }
.orm-hero-visual .fc-1 { top: 16px; left: -20px; animation-delay: 0s; }
.orm-hero-visual .fc-2 { bottom: 40px; right: -20px; animation-delay: 3s; }
.floating-card .icon { font-size: 24px; }
.floating-card h4 { margin: 0; font-size: 20px; font-weight: 800; color: #1c1917; }
.floating-card span { font-size: 13px; color: #57534e; font-weight: 500; }
@keyframes float { 0% { transform: translateY(0px); } 50% { transform: translateY(-15px); } 100% { transform: translateY(0px); } }
.hero-decor-circle { position: absolute; width: 600px; height: 600px; border-radius: 50%; background: radial-gradient(circle, rgba(124,58,237,0.05) 0%, rgba(255,255,255,0) 70%); top: -100px; right: -100px; z-index: 1; }

/* ════════════════════════════════════════════════════
   ZONE B: THE COST OF A DAMAGED REPUTATION — Light
   Industry damage calculator + cascade visual
═════════════════════════════════════════════════════ */
.orm-cost-section { background: #ffffff; padding: 90px 0; }
.orm-cost-header { margin-bottom: 56px; }
.orm-cost-header .sec-tag { display: inline-block; background: rgba(239,68,68,.15); color: #dc2626; font-size: 12px; font-weight: 800; padding: 5px 16px; border-radius: 20px; text-transform: uppercase; letter-spacing: .8px; margin-bottom: 16px; border: 1px solid rgba(239,68,68,.25); }
.orm-cost-header h2 { font-size: clamp(26px, 3vw, 42px); font-weight: 900; color: #1c1917; margin-bottom: 12px; }
.orm-cost-header p { font-size: 16px; color: #57534e; max-width: 680px; }
/* 2-col layout: cascade left, industry cards right */
.orm-cost-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 48px; align-items: start; }
@media (max-width: 991px) { .orm-cost-grid { grid-template-columns: 1fr; gap: 36px; } }
/* Cascade visual — reputation health meter */
.orm-cascade { }
.orm-cascade h4 { font-size: 16px; font-weight: 700; color: #1c1917; text-transform: uppercase; letter-spacing: .8px; margin-bottom: 24px; }
.orm-cascade-step { display: flex; gap: 16px; margin-bottom: 0; position: relative; }
.orm-cascade-step:not(:last-child)::after { content: '↓'; position: absolute; left: 19px; bottom: -20px; font-size: 18px; color: rgba(239,68,68,.5); font-weight: 700; }
.orm-cascade-step .cs-dot { width: 40px; height: 40px; border-radius: 50%; flex-shrink: 0; display: flex; align-items: center; justify-content: center; font-size: 16px; margin-top: 4px; }
.orm-cascade-step .cs-body { padding-bottom: 28px; }
.orm-cascade-step .cs-body strong { display: block; font-size: 15px; font-weight: 800; margin-bottom: 4px; }
.orm-cascade-step .cs-body p { font-size: 13px; color: #57534e; margin: 0; line-height: 1.5; }
.orm-cascade-step.s1 .cs-dot { background: rgba(239,68,68,.2); border: 1.5px solid rgba(239,68,68,.5); color: #dc2626; }
.orm-cascade-step.s1 .cs-body strong { color: #dc2626; }
.orm-cascade-step.s2 .cs-dot { background: rgba(249,115,22,.2); border: 1.5px solid rgba(249,115,22,.5); color: #ea580c; }
.orm-cascade-step.s2 .cs-body strong { color: #ea580c; }
.orm-cascade-step.s3 .cs-dot { background: rgba(234,179,8,.2); border: 1.5px solid rgba(234,179,8,.5); color: #ca8a04; }
.orm-cascade-step.s3 .cs-body strong { color: #ca8a04; }
.orm-cascade-step.s4 .cs-dot { background: rgba(239,68,68,.15); border: 1.5px solid rgba(239,68,68,.4); color: #dc2626; }
.orm-cascade-step.s4 .cs-body strong { color: #dc2626; }
.orm-cascade-step.s5 .cs-dot { background: rgba(124,58,237,.15); border: 1.5px solid rgba(124,58,237,.4); color: #7c3aed; }
.orm-cascade-step.s5 .cs-body strong { color: #7c3aed; }
/* Industry damage cards */
.orm-industry-costs h4 { font-size: 16px; font-weight: 700; color: #1c1917; text-transform: uppercase; letter-spacing: .8px; margin-bottom: 24px; }
.orm-cost-card { background: #fff; border: 1px solid var(--orm-border); border-radius: 14px; padding: 20px 22px; margin-bottom: 12px; display: flex; align-items: center; gap: 16px; transition: all .3s; box-shadow: 0 4px 16px rgba(0,0,0,.03); }
.orm-cost-card:hover { border-color: rgba(124,58,237,.3); background: rgba(124,58,237,.06); }
.orm-cost-card .cc-icon { font-size: 32px; flex-shrink: 0; }
.orm-cost-card .cc-info { flex: 1; }
.orm-cost-card .cc-info .cc-industry { font-size: 14px; font-weight: 700; color: #1c1917; margin-bottom: 2px; }
.orm-cost-card .cc-info .cc-note { font-size: 12px; color: #57534e; }
.orm-cost-card .cc-loss { text-align: right; }
.orm-cost-card .cc-loss .cc-amt { font-size: 22px; font-weight: 900; color: #dc2626; }
.orm-cost-card .cc-loss .cc-lbl { font-size: 10px; color: #78716c; text-transform: uppercase; letter-spacing: .5px; }
/* Bottom stat strip */
.orm-cost-strip { margin-top: 48px; background: linear-gradient(135deg, #fff5f5, #f5f3ff); border: 1px solid var(--orm-border); border-radius: 16px; padding: 28px 36px; display: flex; align-items: center; justify-content: space-between; flex-wrap: wrap; gap: 16px; }
.orm-cost-strip .strip-text h3 { color: #1c1917; font-size: 19px; font-weight: 800; margin: 0 0 6px; }
.orm-cost-strip .strip-text p { color: #57534e; font-size: 14px; margin: 0; }
.orm-cost-strip a { display: inline-block; background: var(--orm-primary); color: #fff; font-size: 14px; font-weight: 700; padding: 12px 28px; border-radius: 6px; text-decoration: none; white-space: nowrap; transition: all .3s; }
.orm-cost-strip a:hover { background: var(--orm-accent); color: #fff; }

/* ════════════════════════════════════════════════════
   ZONE C: REPUTATION MONITORING RADAR — Light
   8 monitoring platforms in orbit-style grid
═════════════════════════════════════════════════════ */
.orm-radar-section { background: var(--orm-light); padding: 90px 0; }
.orm-radar-header { text-align: center; margin-bottom: 52px; }
.orm-radar-header h2 { font-size: clamp(24px, 2.8vw, 38px); font-weight: 900; color: #1c1917; margin-bottom: 12px; }
.orm-radar-header p { font-size: 16px; color: var(--orm-text); max-width: 640px; margin: 0 auto; }
/* 4×2 platform grid */
.orm-radar-grid { display: grid; grid-template-columns: repeat(4, 1fr); gap: 16px; }
@media (max-width: 991px) { .orm-radar-grid { grid-template-columns: repeat(2, 1fr); } }
@media (max-width: 575px) { .orm-radar-grid { grid-template-columns: 1fr; } }
.orm-platform-card { background: #fff; border: 1.5px solid var(--orm-border); border-radius: 16px; padding: 24px 20px; transition: all .3s; }
.orm-platform-card:hover { border-color: var(--orm-primary); box-shadow: 0 12px 36px rgba(67,56,202,.1); transform: translateY(-4px); }
.orm-platform-card .plat-icon { font-size: 36px; margin-bottom: 12px; display: block; }
.orm-platform-card .plat-name { font-size: 16px; font-weight: 800; color: #1c1917; margin-bottom: 6px; }
.orm-platform-card .plat-stat { display: inline-block; background: var(--orm-light); color: var(--orm-primary); font-size: 11px; font-weight: 800; padding: 3px 10px; border-radius: 12px; border: 1px solid var(--orm-border); margin-bottom: 10px; }
.orm-platform-card .plat-risk { font-size: 12px; color: #dc2626; font-weight: 600; margin-bottom: 6px; display: flex; align-items: center; gap: 6px; }
.orm-platform-card .plat-risk::before { content: '⚠️'; font-size: 12px; }
.orm-platform-card .plat-monitor { font-size: 12px; color: var(--orm-text); }
.orm-platform-card .plat-monitor::before { content: '✓ '; color: var(--orm-primary); font-weight: 800; }
/* Central CTA inside radar section */
.orm-radar-centre { margin-top: 40px; background: #fff; border-radius: 16px; padding: 28px 36px; border: 1.5px solid var(--orm-border); display: flex; align-items: center; justify-content: space-between; flex-wrap: wrap; gap: 16px; }
.orm-radar-centre p { font-size: 15px; font-weight: 600; color: #1c1917; margin: 0; }
.orm-radar-centre a { display: inline-block; background: var(--orm-grad); color: #fff; font-size: 14px; font-weight: 700; padding: 12px 28px; border-radius: 6px; text-decoration: none; transition: all .3s; white-space: nowrap; }
.orm-radar-centre a:hover { opacity: .88; }

/* ════════════════════════════════════════════════════
   ZONE D: PROACTIVE vs CRISIS ORM — Light two-col split
═════════════════════════════════════════════════════ */
.orm-proactive-section { background: var(--orm-cream); padding: 90px 0; }
.orm-proactive-header { text-align: center; margin-bottom: 52px; }
.orm-proactive-header h2 { font-size: clamp(24px, 2.8vw, 38px); font-weight: 900; color: #1c1917; margin-bottom: 12px; }
.orm-proactive-header p { font-size: 16px; color: #57534e; max-width: 640px; margin: 0 auto; }
.orm-split-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 24px; }
@media (max-width: 767px) { .orm-split-grid { grid-template-columns: 1fr; } }
.orm-split-panel { border-radius: 20px; overflow: hidden; }
.orm-split-panel.proactive { background: #fff; border: 1.5px solid var(--orm-primary); box-shadow: 0 10px 30px rgba(0,0,0,.03); }
.orm-split-panel.crisis { background: #fff; border: 1.5px solid rgba(220,38,38,.25); box-shadow: 0 10px 30px rgba(0,0,0,.03); }
.orm-split-panel .panel-header { padding: 24px 28px 18px; border-bottom: 1px solid var(--orm-border); display: flex; align-items: center; gap: 14px; }
.orm-split-panel .panel-header .ph-icon { font-size: 32px; }
.orm-split-panel .panel-header h4 { font-size: 19px; font-weight: 800; color: #1c1917; margin: 0; }
.orm-split-panel.proactive .panel-header { background: rgba(67,56,202,.05); }
.orm-split-panel.crisis .panel-header { background: rgba(220,38,38,.05); }
.orm-split-panel .panel-badge { display: inline-block; font-size: 11px; font-weight: 800; padding: 3px 12px; border-radius: 20px; text-transform: uppercase; letter-spacing: .6px; margin-top: 8px; }
.orm-split-panel.proactive .panel-badge { background: rgba(67,56,202,.1); color: var(--orm-primary); }
.orm-split-panel.crisis .panel-badge { background: rgba(220,38,38,.1); color: #dc2626; }
.orm-action-list { padding: 8px 28px 24px; list-style: none; margin: 0; }
.orm-action-item { padding: 14px 0; border-bottom: 1px solid var(--orm-border); display: flex; align-items: flex-start; gap: 14px; }
.orm-action-item:last-child { border-bottom: none; }
.orm-action-item .ai-icon { font-size: 22px; flex-shrink: 0; margin-top: 2px; }
.orm-action-item .ai-body .ai-title { font-size: 14px; font-weight: 700; color: #1c1917; margin-bottom: 3px; }
.orm-action-item .ai-body .ai-desc { font-size: 12px; color: #57534e; line-height: 1.5; }
.orm-action-item .ai-time { font-size: 11px; font-weight: 700; white-space: nowrap; padding: 3px 8px; border-radius: 10px; flex-shrink: 0; margin-top: 4px; }
.orm-split-panel.proactive .ai-time { background: rgba(67,56,202,.1); color: var(--orm-primary); }
.orm-split-panel.crisis .ai-time { background: rgba(220,38,38,.1); color: #dc2626; }
/* 15-minute rule strip */
.orm-rule-strip { margin-top: 32px; background: var(--orm-grad); border-radius: 14px; padding: 28px 36px; text-align: center; }
.orm-rule-strip h3 { color: #fff; font-size: 22px; font-weight: 900; margin-bottom: 10px; }
.orm-rule-strip p { color: rgba(255,255,255,.85); font-size: 15px; margin: 0; }

/* ════════════════════════════════════════════════════
   ZONE E: 4-PILLAR ORM FRAMEWORK — Light cream
═════════════════════════════════════════════════════ */
.orm-pillars-section { background: var(--orm-cream); padding: 90px 0; }
.orm-pillars-header { text-align: center; margin-bottom: 52px; }
.orm-pillars-header h2 { font-size: clamp(24px, 2.8vw, 38px); font-weight: 900; color: #1c1917; margin-bottom: 12px; }
.orm-pillars-header p { font-size: 16px; color: var(--orm-text); max-width: 640px; margin: 0 auto; }
.orm-pillars-flow { display: grid; grid-template-columns: repeat(4, 1fr); gap: 0; position: relative; }
@media (max-width: 991px) { .orm-pillars-flow { grid-template-columns: repeat(2, 1fr); gap: 20px; } }
@media (max-width: 575px) { .orm-pillars-flow { grid-template-columns: 1fr; } }
.orm-pillar { background: #fff; border: 1.5px solid var(--orm-border); border-radius: 0; padding: 32px 24px; position: relative; transition: all .3s; }
.orm-pillar:first-child { border-radius: 16px 0 0 16px; }
.orm-pillar:last-child { border-radius: 0 16px 16px 0; }
.orm-pillar:not(:last-child) { border-right: none; }
@media (max-width: 991px) { .orm-pillar, .orm-pillar:first-child, .orm-pillar:last-child { border-radius: 16px; border-right: 1.5px solid var(--orm-border); } }
.orm-pillar:hover { background: var(--orm-light); z-index: 2; box-shadow: 0 8px 32px rgba(67,56,202,.12); }
/* Connector arrow */
.orm-pillar:not(:last-child)::after { content: '→'; position: absolute; right: -16px; top: 50%; transform: translateY(-50%); font-size: 22px; color: var(--orm-muted); z-index: 3; font-weight: 700; }
@media (max-width: 991px) { .orm-pillar::after { display: none; } }
.orm-pillar .pillar-num { font-size: 11px; font-weight: 800; text-transform: uppercase; letter-spacing: 1px; color: var(--orm-muted); margin-bottom: 12px; }
.orm-pillar .pillar-icon { font-size: 44px; margin-bottom: 14px; display: block; }
.orm-pillar h5 { font-size: 20px; font-weight: 900; background: var(--orm-grad); -webkit-background-clip: text; -webkit-text-fill-color: transparent; background-clip: text; margin-bottom: 12px; }
.orm-pillar p { font-size: 13px; color: var(--orm-text); line-height: 1.65; margin-bottom: 16px; }
.orm-pillar .pillar-actions { list-style: none; padding: 0; margin: 0; }
.orm-pillar .pillar-actions li { font-size: 12px; color: #44403c; padding: 5px 0; border-bottom: 1px solid #f1efff; display: flex; align-items: center; gap: 8px; }
.orm-pillar .pillar-actions li::before { content: '✓'; color: var(--orm-primary); font-weight: 800; flex-shrink: 0; }
.orm-pillar .pillar-actions li:last-child { border-bottom: none; }

/* ════════════════════════════════════════════════════
   ZONE G: REPUTATION STRATEGY BLUEPRINT — White
═════════════════════════════════════════════════════ */
.orm-blueprint-section { background: #fff; padding: 90px 0; }
.orm-blueprint-header { margin-bottom: 48px; }
.orm-blueprint-header h2 { font-size: clamp(24px, 2.8vw, 38px); font-weight: 900; color: #1c1917; margin-bottom: 12px; }
.orm-blueprint-header p { font-size: 16px; color: var(--orm-text); max-width: 680px; }
.orm-doc-card { border-radius: 18px; overflow: hidden; height: 100%; border: 1.5px solid #e7e5e4; transition: all .3s; }
.orm-doc-card:hover { box-shadow: 0 16px 48px rgba(0,0,0,.08); transform: translateY(-4px); }
.orm-doc-card .dc-bar { height: 6px; }
.orm-doc-card.audit .dc-bar { background: #3b82f6; }
.orm-doc-card.strategy .dc-bar { background: var(--orm-primary); }
.orm-doc-card.reporting .dc-bar { background: var(--orm-accent); }
.orm-doc-card .dc-header { padding: 24px 24px 16px; border-bottom: 1px solid #f5f5f4; }
.orm-doc-card .dc-icon { font-size: 36px; margin-bottom: 10px; display: block; }
.orm-doc-card h5 { font-size: 17px; font-weight: 800; color: #1c1917; margin-bottom: 4px; }
.orm-doc-card .dc-sub { font-size: 13px; color: var(--orm-text); }
.orm-doc-card .dc-body { padding: 20px 24px 24px; }
.orm-doc-lines { list-style: none; padding: 0; margin: 0; }
.orm-doc-lines li { display: flex; align-items: flex-start; gap: 10px; padding: 10px 0; border-bottom: 1px solid #f5f5f4; font-size: 14px; color: #44403c; }
.orm-doc-lines li:last-child { border-bottom: none; }
.orm-doc-lines li .dl-icon { font-size: 16px; flex-shrink: 0; margin-top: 1px; }
.orm-doc-lines li.highlight { color: var(--orm-primary); font-weight: 600; }
.orm-doc-cta { display: block; margin: 16px 0 0; text-align: center; background: var(--orm-light); color: var(--orm-primary); font-size: 14px; font-weight: 700; padding: 12px; border-radius: 10px; text-decoration: none; border: 1.5px solid var(--orm-border); transition: all .3s; }
.orm-doc-cta:hover { background: var(--orm-primary); color: #fff; border-color: var(--orm-primary); }

/* SHARED SECTIONS */
.orm-industries-section { padding: 90px 0; background: #ffffff; }
.orm-industries-list { list-style: none; padding: 0; margin: 0; border-top: 1px solid var(--orm-border); }
.orm-industries-list li a { display: flex; align-items: center; justify-content: space-between; padding: 22px 0; border-bottom: 1px solid var(--orm-border); text-decoration: none; color: #1c1917; font-size: 18px; font-weight: 600; transition: all .3s; }
.orm-industries-list li a:hover { color: var(--orm-primary); padding-left: 12px; }
.orm-industries-list li a .ind-left { display: flex; align-items: center; }
.orm-industries-list li a .ind-icon { font-size: 24px; margin-right: 18px; }
.orm-industries-list li a .ind-arrow { width: 36px; height: 36px; border-radius: 50%; background: var(--orm-light); display: flex; align-items: center; justify-content: center; transition: all .3s; flex-shrink: 0; }
.orm-industries-list li a:hover .ind-arrow { background: var(--orm-primary); }
.orm-testimonials-section { padding: 90px 0; background: var(--orm-light); }
.orm-global-section { padding: 80px 0; background: var(--orm-light); }
.orm-global-section h2 { color: #1c1917; }
.orm-global-section p { color: #57534e; }
.region-badge-orm { display: inline-block; background: #fff; border: 1px solid var(--orm-border); border-radius: 30px; padding: 8px 20px; font-size: 14px; color: #1c1917; margin: 6px 4px; transition: all .3s; }
.region-badge-orm:hover { background: var(--orm-primary); border-color: var(--orm-primary); color: #fff; }
.orm-faq-section { padding: 80px 0; background: var(--orm-light); }
.orm-faq-section .accordion-item { border: 1.5px solid var(--orm-border); border-radius: 12px !important; margin-bottom: 14px; overflow: hidden; }
.orm-faq-section .accordion-button { font-size: 16px; font-weight: 600; color: #1c1917; background: #fff; padding: 20px 24px; }
.orm-faq-section .accordion-button:not(.collapsed) { color: var(--orm-primary); background: var(--orm-light); box-shadow: none; }
.orm-faq-section .accordion-body { font-size: 15px; color: #57534e; padding: 18px 24px 22px; background: var(--orm-light); }
.orm-final-cta { padding: 100px 0; background: var(--orm-cream); text-align: center; position: relative; overflow: hidden; }
.orm-final-cta::before { content: 'REPUTATION'; position: absolute; font-size: 140px; font-weight: 900; color: rgba(0,0,0,.02); left: 50%; transform: translateX(-50%); top: 50%; margin-top: -60px; white-space: nowrap; pointer-events: none; letter-spacing: -4px; }
.orm-final-cta h2 { font-size: clamp(26px, 3.5vw, 48px); font-weight: 900; color: #1c1917; margin-bottom: 20px; position: relative; z-index: 1; }
.orm-final-cta h2 .cta-indigo { color: var(--orm-primary); }
.orm-final-cta p { font-size: 17px; color: #57534e; max-width: 680px; margin: 0 auto 40px; position: relative; z-index: 1; line-height: 1.75; }
.orm-final-cta .cta-phone { font-size: 18px; font-weight: 700; margin-bottom: 32px; position: relative; z-index: 1; color: #1c1917; }
.orm-final-cta .cta-phone a { color: var(--orm-primary); text-decoration: none; }
.orm-cta-actions { display: flex; justify-content: center; gap: 16px; flex-wrap: wrap; position: relative; z-index: 1; }
.orm-cta-btn { display: inline-block; background: var(--orm-grad); color: #fff; font-size: 16px; font-weight: 700; padding: 18px 40px; border-radius: 6px; text-decoration: none; transition: all .3s; }
.orm-cta-btn:hover { opacity: .88; transform: translateY(-2px); color: #fff; }
.orm-cta-btn.ghost { background: transparent; border: 2px solid var(--orm-primary); color: var(--orm-primary); border-radius: 6px; }
.orm-cta-btn.ghost:hover { border-color: var(--orm-primary); background: var(--orm-primary); color: #fff; }
.orm-final-badge { display: inline-flex; align-items: center; gap: 10px; background: #fff; border: 1px solid var(--orm-border); border-radius: 8px; padding: 16px 28px; margin-top: 40px; font-size: 14px; color: #57534e; position: relative; z-index: 1; box-shadow: 0 4px 16px rgba(0,0,0,.03); }
/* Inline tag utility */
.orm-tag { display: inline-block; background: rgba(67,56,202,.1); color: var(--orm-primary); font-size: 12px; font-weight: 800; padding: 5px 16px; border-radius: 20px; text-transform: uppercase; letter-spacing: .8px; margin-bottom: 14px; border: 1px solid rgba(67,56,202,.2); }
/* TESTIMONIAL FIXES */
.orm-testimonials-section .swiper-slide { height: auto; }
.orm-testimonials-section .testimonial-card3 { height: 100%; }
.orm-testimonials-section .testimonial-card3 .testimonial-content-wrap { background-image: none !important; -webkit-mask-image: none !important; mask-image: none !important; background-color: #fff; border: 1px solid var(--orm-border); border-radius: 16px; padding: 35px 30px; box-shadow: 0 10px 30px rgba(0,0,0,.03); height: 100%; display: flex; flex-direction: column; }
.orm-testimonials-section .testimonial-card3 .testimonial-content-wrap p { font-size: 15px !important; line-height: 1.7 !important; font-weight: 400 !important; color: #57534e !important; margin-top: 16px !important; font-family: inherit !important; }
.orm-testimonials-section .testimonial-card3 .testimonial-content-wrap > span { font-size: 17px !important; font-weight: 700 !important; color: #1c1917 !important; line-height: 1.4 !important; display: block !important; margin-bottom: 0 !important; }

/* Pricing */
.orm-pricing-section { padding: 90px 0; background: linear-gradient(180deg, #fff, var(--orm-light)); }
.orm-pricing-section .section-title.four.text-center { margin-bottom: 44px; }
.orm-pricing-section .section-title.four.text-center h2 { font-size: clamp(26px, 3vw, 36px); font-weight: 900; color: var(--orm-dark); margin: 14px 0 12px; }
.orm-pricing-section .section-title.four.text-center p { font-size: 16px; color: var(--orm-text); max-width: 760px; margin: 0 auto; line-height: 1.7; }
.orm-pricing-section .section-title .title-tag { display: inline-block; background: rgba(67,56,202,.1); color: var(--orm-primary); font-size: 13px; font-weight: 700; padding: 5px 18px; border-radius: 20px; margin-bottom: 14px; text-transform: uppercase; letter-spacing: .6px; border: 1px solid rgba(67,56,202,.2); }
.orm-pricing-note { max-width: 980px; margin: 0 auto 34px; padding: 18px 22px; border-radius: 24px; background: linear-gradient(135deg, rgba(67,56,202,.08), rgba(124,58,237,.07)); border: 1px solid var(--orm-border); display: flex; gap: 10px; align-items: flex-start; text-align: left; }
.orm-pricing-note strong { color: var(--orm-dark); font-size: 18px; flex-shrink: 0; }
.orm-pricing-note span { color: var(--orm-text); font-size: 15px; line-height: 1.6; }
.orm-package { position: relative; border-radius: 34px; background: #fff; border: 1px solid var(--orm-border); box-shadow: 0 18px 42px rgba(7,17,31,.07); overflow: hidden; transition: .25s; height: 100%; display: flex; flex-direction: column; }
.orm-package:hover { transform: translateY(-6px); box-shadow: 0 26px 75px rgba(67,56,202,.12); }
.orm-package.orm-featured { border: 2px solid rgba(67,56,202,.35); transform: translateY(-10px); }
.orm-package.orm-featured:before { content: "Most Popular"; position: absolute; right: 22px; top: 20px; padding: 7px 13px; border-radius: 999px; background: var(--orm-primary); color: #fff; font-size: 12px; font-weight: 900; z-index: 2; }
.orm-package-head { padding: 30px; background: linear-gradient(135deg, rgba(67,56,202,.08), rgba(124,58,237,.08)); }
.orm-package-head span { display: inline-flex; padding: 7px 12px; border-radius: 999px; background: #fff; color: var(--orm-primary); font-size: 12px; font-weight: 900; margin-bottom: 14px; }
.orm-package-head h3 { margin: 0 0 8px; color: var(--orm-dark); font-size: 25px; font-weight: 800; }
.orm-package-head p { margin: 0; color: var(--orm-text); font-size: 15px; }
.orm-package-body { padding: 28px 30px 32px; display: flex; flex-direction: column; flex-grow: 1; }
.orm-price { font-size: 34px; line-height: 1; font-weight: 900; color: var(--orm-dark); margin-bottom: 8px; }
.orm-package-body small { color: #667085; font-weight: 600; }
.orm-package ul { padding: 0; margin: 22px 0 0; list-style: none; color: var(--orm-text); display: grid; gap: 10px; flex-grow: 1; }
.orm-package li { display: flex; gap: 8px; align-items: flex-start; font-size: 14.5px; }
.orm-package li:before { content: "✓"; color: var(--orm-primary); font-weight: 900; flex-shrink: 0; }
.orm-ideal { margin: 20px 0; padding: 16px; border-radius: 20px; background: rgba(67,56,202,.06); border: 1px solid var(--orm-border); font-weight: 800; color: var(--orm-dark); font-size: 14px; }
.orm-package .orm-btn-light { background: #fff; color: var(--orm-dark); border: 1px solid var(--orm-border); box-shadow: 0 12px 24px rgba(7,17,31,.06); width: 100%; text-align: center; padding: 15px 24px; border-radius: 999px; font-weight: 900; display: inline-block; text-decoration: none; }
.orm-package .orm-btn-main { background: var(--orm-primary); color: #fff; width: 100%; text-align: center; padding: 15px 24px; border-radius: 999px; font-weight: 900; display: inline-block; text-decoration: none; box-shadow: 0 18px 34px rgba(67,56,202,.24); }
.orm-pricing-guide { max-width: 980px; margin: 40px auto 0; text-align: left; }
.orm-plan-guide-card { position: relative; overflow: hidden; border-radius: 34px; background: #fff; border: 1px solid var(--orm-border); box-shadow: 0 18px 45px rgba(7,17,31,.08); padding: 28px; }
.orm-plan-guide-card:before { content: ""; position: absolute; inset: 0 0 auto; height: 5px; background: var(--orm-primary); }
.orm-plan-guide-card h3 { margin: 0 0 8px; color: var(--orm-dark); font-size: 26px; font-weight: 800; }
.orm-plan-guide-card > p { margin: 0 0 22px; color: var(--orm-text); }
.orm-plan-guide-list { display: grid; gap: 14px; }
.orm-plan-guide-item { display: grid; grid-template-columns: 54px 1fr; gap: 14px; align-items: start; padding: 16px; border-radius: 22px; background: #f8fafc; border: 1px solid #e7ebf3; }
.orm-plan-guide-num { width: 54px; height: 54px; border-radius: 18px; display: grid; place-items: center; background: rgba(67,56,202,.10); color: var(--orm-primary); font-weight: 900; }
